class OAuth2Client {
  constructor(config) {
    this.clientId = config.clientId;
    this.clientSecret = config.clientSecret;
    this.redirectUri = config.redirectUri;
    this.authorizationEndpoint = config.authorizationEndpoint;
    this.tokenEndpoint = config.tokenEndpoint;
    this.scopes = config.scopes || ['openid', 'profile', 'email'];
  }

  async getAuthorizationUrl() {
    const params = new URLSearchParams({
      response_type: 'code',
      client_id: this.clientId,
      redirect_uri: this.redirectUri,
      scope: this.scopes.join(' '),
      state: this.generateState(),
    });
    return `${this.authorizationEndpoint}?${params.toString()}`;
  }

  generateState() {
    return Math.random().toString(36).substring(2, 15) + 
           Math.random().toString(36).substring(2, 15);
  }

  async exchangeCodeForToken(code) {
    const response = await fetch(this.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': 'Basic ' + btoa(`${this.clientId}:${this.clientSecret}`)
      },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: this.redirectUri
      })
    });

    if (!response.ok) {
      throw new Error(`Token exchange failed: ${response.status}`);
    }

    const tokenData = await response.json();
    this.storeTokens(tokenData);
    return tokenData;
  }

  async refreshAccessToken(refreshToken) {
    const response = await fetch(this.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': 'Basic ' + btoa(`${this.clientId}:${this.clientSecret}`)
      },
      body: new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: refreshToken
      })
    });

    if (!response.ok) {
      throw new Error(`Token refresh failed: ${response.status}`);
    }

    const tokenData = await response.json();
    this.storeTokens(tokenData);
    return tokenData;
  }

  storeTokens(tokenData) {
    localStorage.setItem('access_token', tokenData.access_token);
    localStorage.setItem('refresh_token', tokenData.refresh_token);
    localStorage.setItem('token_expires_at', 
      Date.now() + (tokenData.expires_in * 1000));
  }

  getAccessToken() {
    return localStorage.getItem('access_token');
  }

  isTokenExpired() {
    const expiresAt = localStorage.getItem('token_expires_at');
    if (!expiresAt) return true;
    return Date.now() >= parseInt(expiresAt);
  }

  async makeAuthenticatedRequest(url, options = {}) {
    const accessToken = this.getAccessToken();
    if (!accessToken) {
      throw new Error('No access token available');
    }

    if (this.isTokenExpired()) {
      const refreshToken = localStorage.getItem('refresh_token');
      if (refreshToken) {
        await this.refreshAccessToken(refreshToken);
        options.headers = {
          ...options.headers,
          'Authorization': `Bearer ${this.getAccessToken()}`
        };
      } else {
        throw new Error('Token expired and no refresh token available');
      }
    } else {
      options.headers = {
        ...options.headers,
        'Authorization': `Bearer ${accessToken}`
      };
    }

    return fetch(url, options);
  }

  async handleCallback() {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const state = urlParams.get('state');
    const storedState = localStorage.getItem('oauth_state');

    if (!code) {
      throw new Error('Authorization code not found in URL');
    }

    if (state !== storedState) {
      throw new Error('Invalid state parameter');
    }

    try {
      await this.exchangeCodeForToken(code);
      return true;
    } catch (error) {
      console.error('OAuth2 authentication failed:', error);
      throw error;
    }
  }

  logout() {
    localStorage.removeItem('access_token');
    localStorage.removeItem('refresh_token');
    localStorage.removeItem('token_expires_at');
  }
}

// Usage example
const oauthClient = new OAuth2Client({
  clientId: 'your-client-id',
  clientSecret: 'your-client-secret',
  redirectUri: 'https://yourapp.com/callback',
  authorizationEndpoint: 'https://provider.com/oauth/authorize',
  tokenEndpoint: 'https://provider.com/oauth/token',
  scopes: ['openid', 'profile', 'email']
});

// Redirect to authorization URL
const authUrl = await oauthClient.getAuthorizationUrl();
localStorage.setItem('oauth_state', authUrl.split('state=')[1].split('&')[0]);
window.location.href = authUrl;

// Handle callback
if (window.location.pathname === '/callback') {
  await oauthClient.handleCallback();
}

// Make authenticated API requests
const apiResponse = await oauthClient.makeAuthenticatedRequest(
  'https://api.example.com/data',
  { method: 'GET' }
);